import React from "react";
import { SidebarProps, Menu, SubMenu } from "../types";

/**
 * Componente Sidebar da aplicação
 * Exibe a navegação lateral com menus e submenus
 * 
 * @param menus - Array de menus principais
 * @param onSelect - Função callback chamada ao selecionar um submenu
 */
const Sidebar = ({ menus, onSelect }: SidebarProps) => {
  return (
    <aside className="w-64 border-r bg-gray-50 h-full overflow-y-auto">
      <div className="p-4">
        <h2 className="text-lg font-semibold text-gray-800 mb-4">Navegação</h2>
        
        {/* Lista de menus principais */}
        <nav className="space-y-4">
          {menus.map((menu: Menu) => (
            <div key={menu.id} className="space-y-2">
              {/* Título do menu principal */}
              <h3 className="text-sm font-medium text-gray-700 uppercase tracking-wider">
                {menu.name}
              </h3>
              
              {/* Lista de submenus */}
              {menu.subMenus && menu.subMenus.length > 0 && (
                <div className="ml-2 space-y-1">
                  {menu.subMenus.map((subMenu: SubMenu) => (
                    <button
                      key={subMenu.id}
                      onClick={() => onSelect(subMenu.id)}
                      className="w-full text-left px-3 py-2 text-sm text-gray-600 hover:text-gray-900 hover:bg-gray-200 rounded-md transition-colors duration-200"
                      title={`Navegar para ${subMenu.name}`}
                    >
                      {subMenu.name}
                    </button>
                  ))}
                </div>
              )}
            </div>
          ))}
          
          {/* Mensagem quando não há menus */}
          {menus.length === 0 && (
            <p className="text-sm text-gray-500 italic">
              Nenhum menu disponível
            </p>
          )}
        </nav>
      </div>
    </aside>
  );
};

export default Sidebar;
